#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, k;
    cin >> n >> k;
    vector<int> nums(n);
    for (int i = 0; i < n; ++i) {
        cin >> nums[i];
    }

    if (n == 0) {
        return 0;
    }
    k = k % n;
    vector<int> temp(n);
    for (int i = 0; i < n; ++i) {
        temp[(i + k) % n] = nums[i];
    }

    for (int i = 0; i < n; ++i) {
        cout << temp[i] << (i == n - 1 ? "" : " ");
    }
    cout << endl;
    return 0;
}

