#include <stdio.h>

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    int nums[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &nums[i]);
    }

    if (n == 0) return 0;

    k = k % n;
    int temp[n];

    for (int i = 0; i < n; i++) {
        temp[(i + k) % n] = nums[i];
    }

    for (int i = 0; i < n; i++) {
        printf("%d", temp[i]);
        if (i != n - 1) printf(" ");
    }
    printf("\n");
    return 0;
}

